import React from "react";
import { ArrowUpRight, ArrowDownLeft } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function TransactionHistoryScreen({ transactions = [], openReceipt }) {
  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Transaction History</h1>

      {transactions.length === 0 ? (
        <p className="text-gray-500">No transactions yet.</p>
      ) : (
        <div className="space-y-4">
          {transactions.map((t) => (
            <div
              key={t.id}
              className="flex items-center justify-between bg-white p-4 rounded-xl border border-gray-100 shadow-sm cursor-pointer hover:bg-gray-50"
              onClick={() => openReceipt(t)}
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    t.type === "deposit"
                      ? "bg-emerald-100 text-emerald-600"
                      : t.type === "withdraw"
                      ? "bg-red-100 text-red-600"
                      : "bg-teal-100 text-teal-600"
                  }`}
                >
                  {t.type === "deposit" ? (
                    <ArrowUpRight className="w-5 h-5" />
                  ) : t.type === "withdraw" ? (
                    <ArrowDownLeft className="w-5 h-5" />
                  ) : (
                    "💰"
                  )}
                </div>
                <div>
                  <p className="font-semibold text-gray-800">{t.title}</p>
                  <p className="text-xs text-gray-400">{t.date}</p>
                </div>
              </div>
              <span
                className={`font-bold text-sm ${
                  t.type === "deposit"
                    ? "text-emerald-600"
                    : t.type === "withdraw"
                    ? "text-red-600"
                    : "text-teal-600"
                }`}
              >
                {t.type === "deposit" ? "+" : t.type === "withdraw" ? "-" : ""}${formatCurrency(t.amount)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
